// Core data types for the Tennis Racquet Explorer

export interface Racquet {
  id: string;
  code: string;
  model: string;
  brand: string;

  // Physical specifications
  flex: number;
  swingweight: number;
  length: string;
  head_size: string;
  weight: string;
  balance: string;
  construction: string;
  material: string;
  string_pattern: string;

  // Computed numeric values
  weight_oz?: number;
  length_in?: number;
  head_size_sq_in?: number;
  balance_in?: number;
  balance_pts?: number; // Head light/heavy in points

  // Performance averages (computed from reviews)
  power_avg?: number;
  control_avg?: number;
  comfort_avg?: number;
  maneuverability_avg?: number;
  stability_avg?: number;
  serves_avg?: number;
  returns_avg?: number;
  groundstrokes_avg?: number;
  volleys_avg?: number;
  slice_avg?: number;
  topspin_avg?: number;
  touch_feel_avg?: number;
  overall_avg?: number;

  // Meta information
  review_count?: number;
  created_at?: string;
  updated_at?: string;
}

export interface Review {
  id: string;
  racquet_id: string;
  player_name: string;
  category: string;
  score: number;
  created_at?: string;
}

export interface Brand {
  id: string;
  name: string;
  logo_url?: string;
  description?: string;
  racquet_count?: number;
}

// Performance categories
export const PERFORMANCE_CATEGORIES = [
  'Power',
  'Control', 
  'Comfort',
  'Maneuverability',
  'Stability',
  'Serves',
  'Returns',
  'Groundstrokes',
  'Volleys',
  'Slice',
  'Topspin',
  'Touch/Feel',
  'Overall'
] as const;

export type PerformanceCategory = typeof PERFORMANCE_CATEGORIES[number];

// UI and filter types
export interface FilterState {
  brands: string[];
  weight_range: [number, number];
  head_size_range: [number, number];
  power_range: [number, number];
  control_range: [number, number];
  search_query: string;
}

export interface RacquetWithReviews extends Racquet {
  reviews: Review[];
}

// PCA and visualization types
export interface PCACoordinates {
  x: number;
  y: number;
  z?: number;
}

export interface RacquetVisualization extends Racquet {
  pca: PCACoordinates;
  cluster_id?: number;
}

// API response types
export interface ApiResponse<T> {
  data: T;
  meta?: {
    total: number;
    page: number;
    limit: number;
  };
  error?: string;
}

export interface RacquetFilters {
  brand?: string[];
  weight_min?: number;
  weight_max?: number;
  head_size_min?: number;
  head_size_max?: number;
  power_min?: number;
  power_max?: number;
  control_min?: number;
  control_max?: number;
  search?: string;
  limit?: number;
  offset?: number;
}

