'use client';

import { useState } from 'react';
import { RangeSlider } from './RangeSlider';
import { BrandFilter } from './BrandFilter';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Label } from '@/components/ui/Label';
import { Card } from '@/components/ui/Card';
import { Brand } from '@/lib/types';

interface RacquetFiltersProps {
  brands: Brand[];
  selectedBrands: string[];
  onBrandsChange: (brands: string[]) => void;

  // Range filters
  weightRange: [number, number];
  weightLimits: [number, number];
  onWeightChange: (range: [number, number]) => void;

  headSizeRange: [number, number];
  headSizeLimits: [number, number];
  onHeadSizeChange: (range: [number, number]) => void;

  powerRange: [number, number];
  powerLimits: [number, number];
  onPowerChange: (range: [number, number]) => void;

  controlRange: [number, number];
  controlLimits: [number, number];
  onControlChange: (range: [number, number]) => void;

  comfortRange: [number, number];
  comfortLimits: [number, number];
  onComfortChange: (range: [number, number]) => void;

  // Search
  searchQuery: string;
  onSearchChange: (query: string) => void;

  // Actions
  onReset: () => void;

  // UI state
  isCollapsed?: boolean;
  onToggleCollapse?: () => void;

  // Filter counts
  totalCount: number;
  filteredCount: number;
}

export function RacquetFilters({
  brands,
  selectedBrands,
  onBrandsChange,

  weightRange,
  weightLimits,
  onWeightChange,

  headSizeRange,
  headSizeLimits,
  onHeadSizeChange,

  powerRange,
  powerLimits,
  onPowerChange,

  controlRange,
  controlLimits,
  onControlChange,

  comfortRange,
  comfortLimits,
  onComfortChange,

  searchQuery,
  onSearchChange,

  onReset,

  isCollapsed = false,
  onToggleCollapse,

  totalCount,
  filteredCount,
}: RacquetFiltersProps) {
  const [searchInputValue, setSearchInputValue] = useState(searchQuery);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSearchChange(searchInputValue);
  };

  const handleSearchInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchInputValue(e.target.value);
    // Debounced search - update immediately for responsiveness
    onSearchChange(e.target.value);
  };

  const hasActiveFilters = 
    selectedBrands.length > 0 ||
    JSON.stringify(weightRange) !== JSON.stringify(weightLimits) ||
    JSON.stringify(headSizeRange) !== JSON.stringify(headSizeLimits) ||
    JSON.stringify(powerRange) !== JSON.stringify(powerLimits) ||
    JSON.stringify(controlRange) !== JSON.stringify(controlLimits) ||
    JSON.stringify(comfortRange) !== JSON.stringify(comfortLimits) ||
    searchQuery.length > 0;

  return (
    <Card className="p-6 space-y-6">
      {/* Filter Header */}
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-lg font-semibold text-gray-900">Filters</h3>
          <p className="text-sm text-gray-600">
            {filteredCount} of {totalCount} racquets
          </p>
        </div>

        <div className="flex items-center space-x-2">
          {hasActiveFilters && (
            <Button
              variant="outline"
              size="sm"
              onClick={onReset}
              className="text-sm"
            >
              Clear All
            </Button>
          )}

          {onToggleCollapse && (
            <Button
              variant="outline"
              size="sm"
              onClick={onToggleCollapse}
              className="text-sm"
            >
              {isCollapsed ? 'Expand' : 'Collapse'}
            </Button>
          )}
        </div>
      </div>

      {!isCollapsed && (
        <>
          {/* Search */}
          <div className="space-y-3">
            <Label htmlFor="search" className="text-sm font-medium text-gray-700">
              Search Racquets
            </Label>
            <form onSubmit={handleSearchSubmit}>
              <Input
                id="search"
                type="text"
                placeholder="Search by model, brand, or material..."
                value={searchInputValue}
                onChange={handleSearchInputChange}
                className="w-full"
              />
            </form>
          </div>

          {/* Brand Filter */}
          <BrandFilter
            brands={brands}
            selectedBrands={selectedBrands}
            onChange={onBrandsChange}
          />

          {/* Physical Specifications */}
          <div className="space-y-4">
            <h4 className="text-sm font-medium text-gray-900 border-b pb-2">
              Physical Specifications
            </h4>

            <RangeSlider
              id="weight"
              label="Weight"
              min={weightLimits[0]}
              max={weightLimits[1]}
              step={0.1}
              value={weightRange}
              onChange={onWeightChange}
              unit=" oz"
            />

            <RangeSlider
              id="head-size"
              label="Head Size"
              min={headSizeLimits[0]}
              max={headSizeLimits[1]}
              step={1}
              value={headSizeRange}
              onChange={onHeadSizeChange}
              unit=" sq in"
            />
          </div>

          {/* Performance Ratings */}
          <div className="space-y-4">
            <h4 className="text-sm font-medium text-gray-900 border-b pb-2">
              Performance Ratings
            </h4>

            <RangeSlider
              id="power"
              label="Power"
              min={powerLimits[0]}
              max={powerLimits[1]}
              step={0.1}
              value={powerRange}
              onChange={onPowerChange}
              unit="/10"
            />

            <RangeSlider
              id="control"
              label="Control"
              min={controlLimits[0]}
              max={controlLimits[1]}
              step={0.1}
              value={controlRange}
              onChange={onControlChange}
              unit="/10"
            />

            <RangeSlider
              id="comfort"
              label="Comfort"
              min={comfortLimits[0]}
              max={comfortLimits[1]}
              step={0.1}
              value={comfortRange}
              onChange={onComfortChange}
              unit="/10"
            />
          </div>

          {/* Active Filters Summary */}
          {hasActiveFilters && (
            <div className="pt-4 border-t">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium text-gray-700">
                  Active Filters
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={onReset}
                  className="text-xs"
                >
                  Clear All
                </Button>
              </div>
              <div className="mt-2 space-y-1 text-xs text-gray-600">
                {selectedBrands.length > 0 && (
                  <div>Brands: {selectedBrands.length} selected</div>
                )}
                {JSON.stringify(weightRange) !== JSON.stringify(weightLimits) && (
                  <div>Weight: {weightRange[0]}-{weightRange[1]} oz</div>
                )}
                {JSON.stringify(headSizeRange) !== JSON.stringify(headSizeLimits) && (
                  <div>Head Size: {headSizeRange[0]}-{headSizeRange[1]} sq in</div>
                )}
                {JSON.stringify(powerRange) !== JSON.stringify(powerLimits) && (
                  <div>Power: {powerRange[0]}-{powerRange[1]}/10</div>
                )}
                {JSON.stringify(controlRange) !== JSON.stringify(controlLimits) && (
                  <div>Control: {controlRange[0]}-{controlRange[1]}/10</div>
                )}
                {JSON.stringify(comfortRange) !== JSON.stringify(comfortLimits) && (
                  <div>Comfort: {comfortRange[0]}-{comfortRange[1]}/10</div>
                )}
                {searchQuery && (
                  <div>Search: "{searchQuery}"</div>
                )}
              </div>
            </div>
          )}
        </>
      )}
    </Card>
  );
}

