'use client';

import { useState, useEffect, useRef } from 'react';
import { Label } from '@/components/ui/Label';
import { Input } from '@/components/ui/Input';
import { Button } from '@/components/ui/Button';
import { Brand } from '@/lib/types';

interface BrandFilterProps {
  brands: Brand[];
  selectedBrands: string[];
  onChange: (selected: string[]) => void;
  disabled?: boolean;
}

export function BrandFilter({
  brands,
  selectedBrands,
  onChange,
  disabled = false,
}: BrandFilterProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const [filteredBrands, setFilteredBrands] = useState(brands);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const filtered = brands.filter(brand =>
      brand.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFilteredBrands(filtered);
  }, [searchTerm, brands]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleBrandToggle = (brandId: string) => {
    if (selectedBrands.includes(brandId)) {
      onChange(selectedBrands.filter(id => id !== brandId));
    } else {
      onChange([...selectedBrands, brandId]);
    }
  };

  const handleSelectAll = () => {
    if (selectedBrands.length === filteredBrands.length) {
      onChange([]);
    } else {
      onChange(filteredBrands.map(brand => brand.id));
    }
  };

  const getSelectedBrandNames = () => {
    return brands
      .filter(brand => selectedBrands.includes(brand.id))
      .map(brand => brand.name);
  };

  const selectedNames = getSelectedBrandNames();
  const displayText = selectedNames.length === 0 
    ? 'All brands'
    : selectedNames.length === 1
    ? selectedNames[0]
    : `${selectedNames.length} brands selected`;

  return (
    <div className="space-y-3" ref={dropdownRef}>
      <Label htmlFor="brand-filter" className="text-sm font-medium text-gray-700">
        Brand
      </Label>

      <div className="relative">
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          disabled={disabled}
          className="w-full px-3 py-2 text-left bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-50 disabled:cursor-not-allowed"
        >
          <span className="block truncate">{displayText}</span>
          <span className="absolute inset-y-0 right-0 flex items-center pr-2 pointer-events-none">
            <svg
              className={`w-5 h-5 text-gray-400 transform transition-transform ${isOpen ? 'rotate-180' : ''}`}
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
            >
              <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
            </svg>
          </span>
        </button>

        {isOpen && (
          <div className="absolute z-10 w-full mt-1 bg-white border border-gray-300 rounded-md shadow-lg max-h-60 overflow-auto">
            <div className="p-3 border-b border-gray-200">
              <Input
                type="text"
                placeholder="Search brands..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full"
              />
            </div>

            <div className="p-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleSelectAll}
                className="w-full mb-2"
              >
                {selectedBrands.length === filteredBrands.length ? 'Deselect All' : 'Select All'}
              </Button>

              <div className="space-y-1">
                {filteredBrands.map((brand) => (
                  <label
                    key={brand.id}
                    className="flex items-center space-x-2 p-2 hover:bg-gray-50 rounded cursor-pointer"
                  >
                    <input
                      type="checkbox"
                      checked={selectedBrands.includes(brand.id)}
                      onChange={() => handleBrandToggle(brand.id)}
                      className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
                    />
                    <span className="flex-1 text-sm text-gray-700">
                      {brand.name}
                    </span>
                    <span className="text-xs text-gray-500">
                      ({brand.racquet_count})
                    </span>
                  </label>
                ))}
              </div>

              {filteredBrands.length === 0 && (
                <div className="py-4 text-center text-gray-500 text-sm">
                  No brands found matching "{searchTerm}"
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {selectedNames.length > 0 && (
        <div className="flex flex-wrap gap-2">
          {selectedNames.map((name) => (
            <span
              key={name}
              className="inline-flex items-center px-2 py-1 text-xs bg-blue-100 text-blue-800 rounded-full"
            >
              {name}
              <button
                type="button"
                onClick={() => {
                  const brand = brands.find(b => b.name === name);
                  if (brand) handleBrandToggle(brand.id);
                }}
                className="ml-1 text-blue-600 hover:text-blue-800"
              >
                ×
              </button>
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

